using UnityEngine;
using TowerDefense.Data;
using TowerDefense.Enemy;

namespace TowerDefense.Tower
{
    public class LightningAttack : TowerAttack
    {
        [Header("Lightning Settings")]
        [SerializeField] private int _segments = 12;
        [SerializeField] private float _arcAmplitude = 0.3f;
        [SerializeField] private float _jitterSpeed = 20f;
        [SerializeField] private float _beamWidth = 0.12f;
        [SerializeField] private float _glowWidth = 0.3f;

        [Header("Colors")]
        [SerializeField] private Color _coreColor = new Color(0.9f, 0.7f, 1f, 1f);
        [SerializeField] private Color _glowColor = new Color(0.5f, 0.1f, 0.9f, 0.6f);

        [Header("Damage Timing")]
        [SerializeField] private float _damageInterval = 0.15f;

        private LineRenderer _coreLine;
        private LineRenderer _glowLine;
        private float _damageTimer;
        private Enemy.Enemy _trackedTarget;
        private bool _isFiring;
        private Vector3[] _linePoints;

        protected override void Update()
        {
            base.Update();

            if (_isFiring && _trackedTarget != null && !_trackedTarget.IsDead)
            {
                UpdateLightningVisual();
            }
        }

        public override void Attack(Enemy.Enemy target)
        {
            if (target == null || target.IsDead)
            {
                StopLightning();
                return;
            }

            _trackedTarget = target;

            if (!_isFiring)
            {
                StartLightning();
                _isFiring = true;
                _damageTimer = 0f;
            }

            _damageTimer += Time.deltaTime;
            if (_damageTimer >= _damageInterval)
            {
                _damageTimer = 0f;
                DealDamage(target);
            }
        }

        public override bool CanAttack()
        {
            return _tower != null && _tower.CurrentTarget != null && !_tower.CurrentTarget.IsDead;
        }

        private void DealDamage(Enemy.Enemy target)
        {
            if (target == null || target.IsDead) return;
            float dmg = _tower.CurrentStats.damage;
            target.Health.TakeDamage(Mathf.RoundToInt(dmg), DamageType.Magic);
        }

        private void StartLightning()
        {
            _linePoints = new Vector3[_segments];

            if (_coreLine == null)
            {
                GameObject coreObj = new GameObject("LightningCore");
                coreObj.transform.SetParent(transform);
                coreObj.transform.localPosition = Vector3.zero;
                _coreLine = coreObj.AddComponent<LineRenderer>();
                _coreLine.material = new Material(Shader.Find("Sprites/Default"));
                _coreLine.startColor = _coreColor;
                _coreLine.endColor = _coreColor;
                _coreLine.startWidth = _beamWidth;
                _coreLine.endWidth = _beamWidth;
                _coreLine.positionCount = _segments;
                _coreLine.sortingOrder = 10;
                _coreLine.useWorldSpace = true;
            }

            if (_glowLine == null)
            {
                GameObject glowObj = new GameObject("LightningGlow");
                glowObj.transform.SetParent(transform);
                glowObj.transform.localPosition = Vector3.zero;
                _glowLine = glowObj.AddComponent<LineRenderer>();
                _glowLine.material = new Material(Shader.Find("Sprites/Default"));
                _glowLine.startColor = _glowColor;
                _glowLine.endColor = _glowColor;
                _glowLine.startWidth = _glowWidth;
                _glowLine.endWidth = _glowWidth;
                _glowLine.positionCount = _segments;
                _glowLine.sortingOrder = 9;
                _glowLine.useWorldSpace = true;
            }

            _coreLine.enabled = true;
            _glowLine.enabled = true;
        }

        private void StopLightning()
        {
            _isFiring = false;
            _trackedTarget = null;
            if (_coreLine != null) _coreLine.enabled = false;
            if (_glowLine != null) _glowLine.enabled = false;
        }

        private void UpdateLightningVisual()
        {
            if (_trackedTarget == null || _trackedTarget.IsDead)
            {
                StopLightning();
                return;
            }

            Vector3 start = transform.position;
            Vector3 end = _trackedTarget.transform.position;
            Vector3 dir = end - start;

            for (int i = 0; i < _segments; i++)
            {
                float t = (float)i / (_segments - 1);
                Vector3 point = Vector3.Lerp(start, end, t);

                if (i > 0 && i < _segments - 1)
                {
                    Vector3 perpendicular = new Vector3(-dir.y, dir.x, 0).normalized;
                    float noise = Mathf.PerlinNoise(i * 1.7f + Time.time * _jitterSpeed, 0f) - 0.5f;
                    float amplitude = _arcAmplitude * (1f - Mathf.Abs(t - 0.5f) * 2f);
                    point += perpendicular * noise * amplitude * 2f;
                }

                _linePoints[i] = point;
            }

            _coreLine.SetPositions(_linePoints);
            _glowLine.SetPositions(_linePoints);

            _coreLine.startColor = _coreColor;
            _coreLine.endColor = _coreColor;
            _glowLine.startColor = _glowColor;
            _glowLine.endColor = _glowColor;
        }

        private void OnDisable()
        {
            StopLightning();
        }

        private void OnDestroy()
        {
            if (_coreLine != null) Destroy(_coreLine.gameObject);
            if (_glowLine != null) Destroy(_glowLine.gameObject);
        }
    }
}

using System.Collections;
using UnityEngine;
using TowerDefense.Data;
using TowerDefense.Enemy;

namespace TowerDefense.Tower
{
    public class TowerAttack : MonoBehaviour
    {
        [Header("Attack Settings")]
        [SerializeField] private Transform _firePoint;
        [SerializeField] private bool _autoFire = true;

        protected Tower _tower;
        protected float _attackCooldown = 0f;
        protected bool _canAttack = true;

        public bool CanAttackValue => _canAttack && _attackCooldown <= 0f;

        public virtual void Initialize(Tower tower)
        {
            _tower = tower;
            _attackCooldown = 0f;
        }

        protected virtual void Update()
        {
            if (_attackCooldown > 0)
            {
                _attackCooldown -= Time.deltaTime;
            }
        }

        public virtual bool CanAttack()
        {
            return _attackCooldown <= 0f && _tower.CurrentTarget != null;
        }

        /// <summary>
        /// Returns the effective attack range for targeting purposes.
        /// Projectile towers use their stats range; barracks use soldier engage range.
        /// </summary>
        public virtual float GetEffectiveAttackRange()
        {
            return _tower != null ? _tower.CurrentStats.attackRange : 0f;
        }

        public virtual void Attack(Enemy.Enemy target)
        {
            if (target == null || target.IsDead) return;

            TowerData.TowerStats stats = _tower.CurrentStats;

            switch (_tower.Data.towerType)
            {
                case TowerType.Archer:
                    FireProjectile(target);
                    break;
                case TowerType.Mage:
                    FireMagicAttack(target);
                    break;
                case TowerType.Barracks:
                    SpawnSoldiers(target);
                    break;
                case TowerType.Artillery:
                    FireExplosive(target);
                    break;
                case TowerType.Sword:
                    FirePierceProjectile(target);
                    break;
            }

            // Barracks don't use cooldown - soldiers continuously auto-assign
            if (_tower.Data.towerType != TowerType.Barracks)
            {
                _attackCooldown = 1f / stats.attackSpeed;
            }

            if (_tower.GetComponent<Animator>() != null)
            {
                _tower.GetComponent<Animator>().SetTrigger("Attack");
            }
        }

        protected virtual void FireProjectile(Enemy.Enemy target)
        {
            Debug.Log($"FireProjectile called");
            Debug.Log($"Projectile prefab: " + _tower.Data.projectilePrefab);
            Debug.Log($"FirePoint: " + _firePoint);

            if (_tower.Data.projectilePrefab == null || _firePoint == null)
            {
                if (_tower.Data.projectilePrefab == null)
                {
                    Debug.LogError("Projectile prefab is null!");
                }
                return;
            }

            GameObject projectileObj = Instantiate(
                _tower.Data.projectilePrefab,
                _firePoint.position,
                Quaternion.identity
            );

            Projectile projectile = projectileObj.GetComponent<Projectile>();
            if (projectile != null)
            {
                projectile.Initialize(target, _tower.CurrentStats.damage, DamageType.Physical);
            }
        }

        protected virtual void FireMagicAttack(Enemy.Enemy target)
        {
            if (_tower.Data.projectilePrefab == null || _firePoint == null) return;

            GameObject projectileObj = Instantiate(
                _tower.Data.projectilePrefab,
                _firePoint.position,
                Quaternion.identity
            );

            Projectile projectile = projectileObj.GetComponent<Projectile>();
            if (projectile != null)
            {
                projectile.Initialize(target, _tower.CurrentStats.damage, DamageType.Magic);
            }
        }

        protected virtual void FireExplosive(Enemy.Enemy target)
        {
            if (_tower.Data.projectilePrefab == null || _firePoint == null) return;

            GameObject projectileObj = Instantiate(
                _tower.Data.projectilePrefab,
                _firePoint.position,
                Quaternion.identity
            );

            Projectile projectile = projectileObj.GetComponent<Projectile>();
            if (projectile != null)
            {
                projectile.Initialize(
                    target,
                    _tower.CurrentStats.damage,
                    DamageType.Explosion,
                    _tower.CurrentStats.splashRadius,
                    0,
                    _tower.CurrentStats.maxTargets
                );
            }
        }

        protected virtual void SpawnSoldiers(Enemy.Enemy target)
        {
        }

        protected virtual void FirePierceProjectile(Enemy.Enemy target)
        {
            if (_tower.Data.projectilePrefab == null || _firePoint == null) return;

            TowerData.TowerStats stats = _tower.CurrentStats;

            int pierceCount = stats.pierceCount;
            if (pierceCount <= 0)
            {
                int towerLevel = _tower.CurrentLevel;
                pierceCount = towerLevel switch
                {
                    1 => 3,
                    2 => 5,
                    3 => 7,
                    _ => 3
                };
            }

            GameObject projectileObj = Instantiate(
                _tower.Data.projectilePrefab,
                _firePoint.position,
                Quaternion.identity
            );

            Projectile projectile = projectileObj.GetComponent<Projectile>();
            if (projectile != null)
            {
                projectile.Initialize(target, stats.damage, DamageType.Physical, 0f, pierceCount);
            }
        }

        public void SetFirePoint(Transform firePoint)
        {
            _firePoint = firePoint;
        }
    }
}

using System.Collections.Generic;
using UnityEngine;
using TowerDefense.Core;
using TowerDefense.Data;
using TowerDefense.Enemy;

namespace TowerDefense.Tower
{
    public enum TowerState
    {
        Idle,
        Targeting,
        Attacking,
        Upgrading,
        Selling
    }

    public class Tower : MonoBehaviour
    {
        [Header("References")]
        [SerializeField] protected TowerData _towerData;
        [SerializeField] protected TowerAttack _attack;
        [SerializeField] protected Animator _animator;
        [SerializeField] protected Transform _rotatePart;
        [SerializeField] protected SpriteRenderer _spriteRenderer;

        [Header("Visual")]
        [SerializeField] protected GameObject _rangeIndicator;
        [SerializeField] protected Color _rangeColor = new Color(0, 1, 0, 0.3f);
        [Tooltip("Rotation offset in degrees. Default -90 assumes sprite faces UP. Change to 0 if sprite faces RIGHT.")]
        [SerializeField] protected float _rotationOffset = -90f;

        protected int _currentLevel = 1;
        protected TowerState _currentState = TowerState.Idle;
        protected TowerData.TowerStats _currentStats;
        protected Enemy.Enemy _currentTarget;
        protected TowerSlot _slot;

        public TowerData Data => _towerData;
        public int CurrentLevel => _currentLevel;
        public TowerState State => _currentState;
        public Enemy.Enemy CurrentTarget => _currentTarget;
        public TowerData.TowerStats CurrentStats => _currentStats;
        public TowerSlot Slot => _slot;
        public bool IsMaxLevel => _currentLevel >= _towerData.levels.Length;

        public System.Action<Tower> OnUpgrade;
        public System.Action<Tower> OnSell;
        public System.Action<Enemy.Enemy> OnTargetAcquired;
        public System.Action OnTargetLost;

        protected virtual void Awake()
        {
            if (_attack == null) _attack = GetComponent<TowerAttack>();
            if (_animator == null) _animator = GetComponentInChildren<Animator>();
        }

        public virtual void Initialize(TowerData data, TowerSlot slot)
        {
            _towerData = data;
            _slot = slot;
            _currentLevel = 1;
            _currentStats = data.levels[0];
            _currentState = TowerState.Idle;

            if (_attack != null)
            {
                _attack.Initialize(this);
            }

            UpdateRangeIndicator();
        }

        protected virtual void Update()
        {
            if (_currentState == TowerState.Upgrading || _currentState == TowerState.Selling)
                return;

            FindTarget();

            if (_currentTarget != null)
            {
                RotateTowardsTarget();
                Attack();
            }
        }

        protected virtual void FindTarget()
        {
            float actualAttackRange = _attack != null ? _attack.GetEffectiveAttackRange() : _currentStats.attackRange;

            if (_currentTarget != null && !_currentTarget.IsDead)
            {
                float distance = Vector3.Distance(transform.position, _currentTarget.transform.position);
                if (distance <= actualAttackRange)
                {
                    return;
                }
            }

            _currentTarget = FindBestTarget();

            if (_currentTarget != null)
            {
                _currentState = TowerState.Targeting;
                OnTargetAcquired?.Invoke(_currentTarget);
            }
            else
            {
                _currentState = TowerState.Idle;
                OnTargetLost?.Invoke();
            }
        }

        protected virtual Enemy.Enemy FindBestTarget()
        {
            EnemySpawner spawner = FindObjectOfType<EnemySpawner>();
            if (spawner == null)
            {
                Debug.LogError("EnemySpawner not found!");
                return null;
            }

            float actualAttackRange = _attack != null ? _attack.GetEffectiveAttackRange() : _currentStats.attackRange;
            List<Enemy.Enemy> enemiesInRange = spawner.GetEnemiesInRange(transform.position, actualAttackRange);

            if (enemiesInRange.Count == 0) return null;

            Enemy.Enemy bestTarget = null;
            float bestPriority = float.MinValue;

            foreach (var enemy in enemiesInRange)
            {
                if (enemy == null || enemy.IsDead) continue;

                float priority = CalculateTargetPriority(enemy);
                if (priority > bestPriority)
                {
                    bestPriority = priority;
                    bestTarget = enemy;
                }
            }

            return bestTarget;
        }

        protected virtual float CalculateTargetPriority(Enemy.Enemy enemy)
        {
            EnemyMovement movement = enemy.GetComponent<EnemyMovement>();
            if (movement != null)
            {
                return movement.GetProgressPercent();
            }
            return 0f;
        }

        protected virtual void RotateTowardsTarget()
        {
            if (_currentTarget == null) return;
            if (_towerData != null && (_towerData.towerType == TowerType.Barracks || _towerData.towerType == TowerType.Mage)) return;

            Transform rotateTransform = GetRotateTransform();
            if (rotateTransform == null) return;

            Vector3 direction = _currentTarget.transform.position - rotateTransform.position;
            float angle = Mathf.Atan2(direction.y, direction.x) * Mathf.Rad2Deg + _rotationOffset;
            Quaternion targetRotation = Quaternion.AngleAxis(angle, Vector3.forward);
            rotateTransform.rotation = Quaternion.Slerp(rotateTransform.rotation, targetRotation, 10f * Time.deltaTime);
        }

        /// <summary>
        /// Returns the transform that should rotate towards the target.
        /// Uses _rotatePart if it has a visual (renderer in children), 
        /// otherwise falls back to the sprite renderer's transform.
        /// </summary>
        protected Transform GetRotateTransform()
        {
            if (_rotatePart != null)
            {
                if (_rotatePart.GetComponent<Renderer>() != null || _rotatePart.GetComponentInChildren<Renderer>() != null)
                    return _rotatePart;
            }

            if (_spriteRenderer != null)
                return _spriteRenderer.transform;

            var sr = GetComponent<SpriteRenderer>();
            if (sr != null)
                return sr.transform;

            return _rotatePart;
        }

        protected virtual void Attack()
        {
            if (_attack == null) return;

            if (_attack.CanAttack())
            {
                _currentState = TowerState.Attacking;
                _attack.Attack(_currentTarget);
            }
        }

        public virtual bool Upgrade()
        {
            if (IsMaxLevel) return false;

            TowerData.TowerStats nextLevelStats = _towerData.levels[_currentLevel];
            if (!GameManager.Instance.SpendGold(nextLevelStats.upgradeCost)) return false;

            _currentLevel++;
            _currentStats = nextLevelStats;

            if (_animator != null)
            {
                _animator.SetTrigger("Upgrade");
            }

            UpdateRangeIndicator();
            OnUpgrade?.Invoke(this);
            EventBus.Publish(new TowerUpgradedEvent { Tower = gameObject, Level = _currentLevel });

            return true;
        }

        public virtual void Sell()
        {
            Debug.Log($"📤 Tower.Sell() called for {gameObject.name}");
            Debug.Log($"   sellValue: {_currentStats.sellValue}");
            Debug.Log($"   _slot: {_slot != null}");

            int sellValue = _currentStats.sellValue;
            GameManager.Instance.AddGold(sellValue);
            Debug.Log($"   ✅ Added {sellValue} gold");

            OnSell?.Invoke(this);
            EventBus.Publish(new TowerSoldEvent { Tower = gameObject, Refund = sellValue });

            if (_slot != null)
            {
                _slot.RemoveTower();
                Debug.Log($"   ✅ Called _slot.RemoveTower()");
            }

            Destroy(gameObject);
            Debug.Log($"   ✅ Tower destroyed");
        }

        public int GetUpgradeCost()
        {
            if (IsMaxLevel) return 0;
            return _towerData.levels[_currentLevel].upgradeCost;
        }

        public int GetSellValue()
        {
            return _currentStats.sellValue;
        }

        public void ShowRange()
        {
            if (_rangeIndicator != null)
            {
                _rangeIndicator.SetActive(true);
            }
        }

        public void HideRange()
        {
            if (_rangeIndicator != null)
            {
                _rangeIndicator.SetActive(false);
            }
        }

        protected void UpdateRangeIndicator()
        {
            if (_rangeIndicator != null)
            {
                float scale = _currentStats.attackRange * 2f;
                _rangeIndicator.transform.localScale = new Vector3(scale, scale, 1f);
            }
        }

        private void OnDrawGizmosSelected()
        {
            if (_towerData != null && _currentStats.attackRange > 0)
            {
                Gizmos.color = _rangeColor;
                Gizmos.DrawWireSphere(transform.position, _currentStats.attackRange);
            }
        }
    }
}

using UnityEngine;
using System.Collections;
using System.Collections.Generic;

/// <summary>
/// Procedural 2D lightning bolt with branching forks using LineRenderers.
/// All positions on XY plane (Z=0). Branches spread horizontally.
/// </summary>
public class LightningBolt : MonoBehaviour
{
    [Header("Main Bolt")]
    [SerializeField] private int _segments = 12;
    [SerializeField] private float _jitter = 1.5f;
    [SerializeField] private float _duration = 0.45f;
    [SerializeField] private float _width = 0.5f;

    [Header("Branches")]
    [SerializeField] private int _branchCount = 3;
    [SerializeField] private int _branchSegments = 5;
    [SerializeField] private float _branchJitter = 0.8f;
    [SerializeField] private float _branchWidth = 0.2f;
    [SerializeField] private float _branchLength = 0.35f;

    [Header("Colors")]
    [SerializeField] private Color _coreColor = new Color(0.85f, 0.92f, 1f, 1f);
    [SerializeField] private Color _glowColor = new Color(0.4f, 0.6f, 1f, 0.6f);
    [SerializeField] private Color _tipColor = new Color(0.3f, 0.5f, 1f, 0.1f);

    private LineRenderer _mainLR;
    private List<LineRenderer> _branchLRs = new List<LineRenderer>();
    private float _timer;
    private Vector3 _origin;
    private Vector3 _target;

    public void Fire(Vector3 from, Vector3 to)
    {
        _origin = from;
        _target = to;

        // Main bolt
        _mainLR = CreateLineRenderer("MainBolt", _width, _width * 0.25f, _coreColor, _tipColor);
        GeneratePath2D(_mainLR, from, to, _segments, _jitter);

        // Branches
        for (int i = 0; i < _branchCount; i++)
        {
            float t = Random.Range(0.2f, 0.7f);
            Vector3 branchRoot = Vector3.Lerp(from, to, t);
            // Perpendicular in 2D: rotate direction 90 degrees
            Vector2 dir2D = (to - from);
            Vector2 perp2D = new Vector2(-dir2D.y, dir2D.x).normalized;
            branchRoot += (Vector3)(perp2D * Random.Range(-_jitter, _jitter) * 0.5f);

            // Branch end: spread sideways and slightly toward target direction
            Vector3 branchEnd = branchRoot + (Vector3)(perp2D * Random.Range(-1f, 1f) + new Vector2(dir2D.x * 0.2f, dir2D.y * 0.1f).normalized) * Vector3.Distance(from, to) * _branchLength;

            var branchLR = CreateLineRenderer("Branch_" + i, _branchWidth, _branchWidth * 0.2f, _glowColor, _tipColor);
            GeneratePath2D(branchLR, branchRoot, branchEnd, _branchSegments, _branchJitter);
            _branchLRs.Add(branchLR);
        }

        _timer = _duration;
        StartCoroutine(AnimateBolt());
    }

    private LineRenderer CreateLineRenderer(string name, float startWidth, float endWidth, Color startColor, Color endColor)
    {
        var obj = new GameObject(name);
        obj.transform.SetParent(transform);
        var lr = obj.AddComponent<LineRenderer>();
        var mat = new Material(Shader.Find("Mobile/Particles/Additive"));
        if (mat == null) mat = new Material(Shader.Find("Unlit/Color"));
        lr.material = mat;
        lr.startWidth = startWidth;
        lr.endWidth = endWidth;
        lr.startColor = startColor;
        lr.endColor = endColor;
        lr.useWorldSpace = true;
        lr.sortingOrder = 10; // Render on top of sprites
        lr.positionCount = 0;
        return lr;
    }

    private void GeneratePath2D(LineRenderer lr, Vector3 from, Vector3 to, int segments, float jitter)
    {
        lr.positionCount = segments + 1;
        // 2D perpendicular: swap (dx,dy) -> (-dy, dx)
        Vector2 dir = to - from;
        Vector2 perp = new Vector2(-dir.y, dir.x).normalized;
        if (perp == Vector2.zero) perp = Vector2.right;

        lr.SetPosition(0, from);
        for (int i = 1; i < segments; i++)
        {
            float t = (float)i / segments;
            Vector3 pos = Vector3.Lerp(from, to, t);
            pos += (Vector3)(perp * Random.Range(-jitter, jitter));
            pos.z = 0f; // Stay on Z=0
            lr.SetPosition(i, pos);
        }
        lr.SetPosition(segments, to);
    }

    private IEnumerator AnimateBolt()
    {
        while (_timer > 0f)
        {
            _timer -= Time.deltaTime;
            float alpha = Mathf.Clamp01(_timer / _duration);

            // Main bolt flicker
            _mainLR.startColor = new Color(_coreColor.r, _coreColor.g, _coreColor.b, alpha);
            _mainLR.endColor = new Color(_tipColor.r, _tipColor.g, _tipColor.b, alpha * 0.3f);

            // Re-jitter for flicker effect
            GeneratePath2D(_mainLR, _origin, _target, _segments, _jitter * alpha);

            // Branches fade faster
            foreach (var branch in _branchLRs)
            {
                branch.startColor = new Color(_glowColor.r, _glowColor.g, _glowColor.b, alpha * 0.6f);
                branch.endColor = new Color(_tipColor.r, _tipColor.g, _tipColor.b, alpha * 0.1f);
            }

            yield return null;
        }
        Destroy(gameObject);
    }
}

using UnityEngine;
using System.Collections;
using UnityEngine.UI;
using TowerDefense.Enemy;

/// <summary>
/// Controls the Lightning skill in 2D: shows range circle on activation,
/// follows mouse, releases lightning on click with screen flash and camera shake.
/// All positions and effects operate on the XY plane (Z=0).
/// </summary>
public class LightningSkillController : MonoBehaviour
{
    [Header("Skill Settings")]
    [SerializeField] private float _skillRange = 5f;
    [SerializeField] private int _damage = 50;
    [SerializeField] private int _boltCount = 6;
    [SerializeField] private float _boltInterval = 0.06f;
    [SerializeField] private float _boltHeight = 18f;
    [SerializeField] private float _cooldown = 30f;

    [Header("References")]
    [SerializeField] private GameObject _rangeIndicator;
    [SerializeField] private ParticleSystem _lightningImpactPrefab;
    [SerializeField] private GameObject _lightningBoltPrefab;
    [SerializeField] private Button _skillButton;
    [SerializeField] private Camera _mainCamera;

    [Header("Audio")]
    [SerializeField] private AudioClip _thunderClip;
    [SerializeField] private AudioSource _audioSource;

    [Header("Screen Flash")]
    [SerializeField] private float _flashDuration = 0.15f;
    [SerializeField] private Color _flashColor = new Color(0.4f, 0.6f, 1f, 0.6f);

    [Header("Cooldown Display")]
    [SerializeField] private Text _cooldownText;

    [Header("Camera Shake")]
    [SerializeField] private float _shakeIntensity = 0.4f;
    [SerializeField] private float _shakeDuration = 0.3f;

    [Header("Ground Ring")]
    [SerializeField] private float _ringExpandSpeed = 15f;
    [SerializeField] private float _ringMaxRadius = 8f;
    [SerializeField] private float _ringDuration = 0.8f;

    private bool _skillActive;
    private bool _onCooldown;
    private Vector3 _targetPos;
    private LineRenderer _rangeLR;

    private Vector3 _camOriginalPos;
    private float _shakeTimer;

    private Image _flashImage;
    private float _flashTimer;

    private void Start()
    {
        if (_mainCamera == null) _mainCamera = Camera.main;
        if (_rangeIndicator == null)
        {
            var ri = GameObject.Find("RangeIndicator");
            if (ri == null)
            {
                foreach (var t in Resources.FindObjectsOfTypeAll<Transform>())
                {
                    if (t.name == "RangeIndicator") { ri = t.gameObject; break; }
                }
            }
            if (ri != null) _rangeIndicator = ri;
        }
        if (_rangeIndicator != null)
        {
            _rangeIndicator.SetActive(false);
            _rangeLR = _rangeIndicator.GetComponent<LineRenderer>();
            if (_rangeLR != null) _rangeLR.useWorldSpace = false;
        }
        if (_skillButton == null)
        {
            var btnObj = GameObject.Find("SkillButton_Lightning");
            if (btnObj != null) _skillButton = btnObj.GetComponent<Button>();
        }
        if (_skillButton != null) _skillButton.onClick.AddListener(OnSkillButtonClicked);

        CreateFlashOverlay();
    }

    private void CreateFlashOverlay()
    {
        var canvas = FindObjectOfType<Canvas>();
        if (canvas == null) return;

        var flashObj = new GameObject("ScreenFlash");
        flashObj.transform.SetParent(canvas.transform, false);
        var flashRect = flashObj.AddComponent<RectTransform>();
        flashRect.anchorMin = Vector2.zero;
        flashRect.anchorMax = Vector2.one;
        flashRect.offsetMin = Vector2.zero;
        flashRect.offsetMax = Vector2.zero;

        _flashImage = flashObj.AddComponent<Image>();
        _flashImage.color = new Color(_flashColor.r, _flashColor.g, _flashColor.b, 0f);
        _flashImage.raycastTarget = false;
    }

    private void Update()
    {
        if (_skillActive)
        {
            UpdateRangeIndicator();

            if (Input.GetMouseButtonDown(0))
            {
                ReleaseSkill();
            }
            if (Input.GetMouseButtonDown(1))
            {
                CancelSkill();
            }
        }

        // 2D camera shake (XY only)
        if (_shakeTimer > 0f)
        {
            _shakeTimer -= Time.deltaTime;
            float intensity = _shakeIntensity * (_shakeTimer / _shakeDuration);
            Vector2 offset = Random.insideUnitCircle * intensity;
            _mainCamera.transform.position = _camOriginalPos + new Vector3(offset.x, offset.y, 0f);
        }

        // Screen flash
        if (_flashTimer > 0f)
        {
            _flashTimer -= Time.deltaTime;
            float alpha = (_flashTimer / _flashDuration) * _flashColor.a;
            _flashImage.color = new Color(_flashColor.r, _flashColor.g, _flashColor.b, alpha);
        }
    }

    private void OnSkillButtonClicked()
    {
        if (_onCooldown) return;
        _skillActive = true;
        if (_rangeIndicator != null) _rangeIndicator.SetActive(true);
    }

    private void UpdateRangeIndicator()
    {
        // 2D: convert mouse to world point on Z=0 plane
        // z must be distance from camera to XY plane, otherwise returns camera position
        Vector3 mouseScreen = Input.mousePosition;
        mouseScreen.z = Mathf.Abs(_mainCamera.transform.position.z);
        Vector3 mouseWorld = _mainCamera.ScreenToWorldPoint(mouseScreen);
        mouseWorld.z = 0f;
        _targetPos = mouseWorld;

        if (_rangeIndicator != null)
        {
            _rangeIndicator.transform.position = _targetPos;
        }

        // Pulse range indicator
        if (_rangeLR != null)
        {
            float pulse = 0.6f + 0.4f * Mathf.PingPong(Time.time * 3f, 1f);
            _rangeLR.startColor = new Color(0.3f, 0.6f, 1f, pulse);
            _rangeLR.endColor = new Color(0.3f, 0.6f, 1f, pulse);
        }
    }

    private void ReleaseSkill()
    {
        _skillActive = false;
        if (_rangeIndicator != null) _rangeIndicator.SetActive(false);

        _flashTimer = _flashDuration;
        _camOriginalPos = _mainCamera.transform.position;
        _shakeTimer = _shakeDuration;

        DealDamageToEnemies();
        StartCoroutine(SpawnLightningBolts());
        StartCoroutine(SpawnGroundRing());
        StartCoroutine(CooldownRoutine());
    }

    private void DealDamageToEnemies()
    {
        var hits = Physics2D.OverlapCircleAll(_targetPos, _skillRange);
        foreach (var hit in hits)
        {
            var enemy = hit.GetComponent<Enemy>();
            if (enemy != null && !enemy.IsDead)
            {
                enemy.TakeDamage(_damage);
            }
        }
    }

    private void CancelSkill()
    {
        _skillActive = false;
        if (_rangeIndicator != null) _rangeIndicator.SetActive(false);
    }

    private IEnumerator SpawnLightningBolts()
    {
        // Impact particle at target
        if (_lightningImpactPrefab != null)
        {
            var impact = Instantiate(_lightningImpactPrefab, _targetPos, Quaternion.identity);
            impact.Play(true);
            Destroy(impact.gameObject, impact.main.duration + 1.5f);
        }

        if (_thunderClip != null && _audioSource != null)
        {
            _audioSource.PlayOneShot(_thunderClip);
        }

        // Main bolt: origin is above the target on Y axis
        if (_lightningBoltPrefab != null)
        {
            Vector3 mainOrigin = new Vector3(_targetPos.x, _targetPos.y + _boltHeight, 0f);
            var boltObj = Instantiate(_lightningBoltPrefab);
            var bolt = boltObj.GetComponent<LightningBolt>();
            if (bolt != null) bolt.Fire(mainOrigin, _targetPos);
            else Destroy(boltObj);
        }

        yield return new WaitForSeconds(_boltInterval);

        // Surrounding bolts
        for (int i = 0; i < _boltCount - 1; i++)
        {
            // Random offset in 2D circle around target
            Vector2 offset2D = Random.insideUnitCircle * _skillRange * 0.7f;
            Vector3 boltTarget = new Vector3(_targetPos.x + offset2D.x, _targetPos.y + offset2D.y, 0f);
            Vector3 boltOrigin = new Vector3(boltTarget.x + Random.Range(-1f, 1f), boltTarget.y + _boltHeight + Random.Range(-3f, 3f), 0f);

            if (_lightningBoltPrefab != null)
            {
                var boltObj = Instantiate(_lightningBoltPrefab);
                var bolt = boltObj.GetComponent<LightningBolt>();
                if (bolt != null) bolt.Fire(boltOrigin, boltTarget);
                else Destroy(boltObj);
            }

            yield return new WaitForSeconds(_boltInterval);
        }
    }

    private IEnumerator SpawnGroundRing()
    {
        var ringObj = new GameObject("GroundRing");
        ringObj.transform.position = _targetPos;
        var lr = ringObj.AddComponent<LineRenderer>();
        var mat = new Material(Shader.Find("Mobile/Particles/Additive"));
        if (mat != null) lr.material = mat;
        lr.useWorldSpace = true;
        lr.startWidth = 0.3f;
        lr.endWidth = 0.1f;
        lr.loop = true;
        lr.sortingOrder = 1;

        int ringSegments = 48;
        lr.positionCount = ringSegments + 1;
        float elapsed = 0f;

        while (elapsed < _ringDuration)
        {
            elapsed += Time.deltaTime;
            float t = elapsed / _ringDuration;
            float radius = Mathf.Lerp(0.5f, _ringMaxRadius, t);
            float alpha = 1f - t;

            lr.startColor = new Color(0.4f, 0.7f, 1f, alpha * 0.8f);
            lr.endColor = new Color(0.3f, 0.5f, 1f, alpha * 0.2f);

            // 2D circle on XY plane
            for (int i = 0; i <= ringSegments; i++)
            {
                float angle = (float)i / ringSegments * Mathf.PI * 2f;
                float x = Mathf.Cos(angle) * radius;
                float y = Mathf.Sin(angle) * radius;
                lr.SetPosition(i, new Vector3(_targetPos.x + x, _targetPos.y + y, 0f));
            }

            yield return null;
        }

        Destroy(ringObj);
    }

    private IEnumerator CooldownRoutine()
    {
        _onCooldown = true;
        float remaining = _cooldown;
        while (remaining > 0f)
        {
            remaining -= Time.deltaTime;
            if (_cooldownText != null)
                _cooldownText.text = Mathf.CeilToInt(remaining).ToString() + "s";
            yield return null;
        }
        if (_cooldownText != null)
            _cooldownText.text = "";
        _onCooldown = false;
    }
}

using UnityEngine;
using UnityEngine.UI;
using TowerDefense.Data;
using TowerDefense.Utils;
using TowerDefense.Core;

namespace TowerDefense.Enemy
{
    [RequireComponent(typeof(EnemyMovement), typeof(EnemyHealth))]
    public class Enemy : MonoBehaviour
    {
        [Header("Settings")]
        [SerializeField] private EnemyData _enemyData;

        [Header("Health Bar")]
        [SerializeField] private Slider _healthSlider;
        [SerializeField] private Image _healthFillImage;
        [SerializeField] private Color _lowHealthColor = Color.red;
        [SerializeField] private Color _mediumHealthColor = Color.yellow;
        [SerializeField] private Color _highHealthColor = Color.green;
        [SerializeField] private float _healthBarOffsetY = 1.5f;

        private EnemyMovement _movement;
        private EnemyHealth _health;
        private Canvas _healthCanvas;

        public EnemyData Data => _enemyData;
        public EnemyMovement Movement => _movement;
        public EnemyHealth Health => _health;
        public bool IsDead => _health != null && _health.CurrentHealth <= 0;

        private int _birthWaveId = -1;  // 敌人归属的波次ID

        // 给 EnemySpawner 调用的
        public void SetBirthWaveId(int waveId)
        {
            _birthWaveId = waveId;
        }

        private void Awake()
        {
            _movement = GetComponent<EnemyMovement>();
            _health = GetComponent<EnemyHealth>();

            // 获取血条画布
            if (_healthSlider != null)
            {
                _healthCanvas = _healthSlider.GetComponentInParent<Canvas>();
                _healthSlider.value = 1f;
            }

            if (_enemyData != null)
            {
                Initialize(_enemyData);
            }
        }

        public void Initialize(EnemyData data)
        {
            _enemyData = data;

            if (_health != null)
            {
                _health.Initialize(data.stats.maxHealth, data.stats.goldReward);
                _health.OnHealthChanged += UpdateHealthBar;
                _health.OnDeath += OnDeath;
            }

            if (_movement != null)
            {
                _movement.SetSpeed(data.stats.moveSpeed);
            }

            // 初始化血条
            UpdateHealthBar(data.stats.maxHealth, data.stats.maxHealth);
        }

        public void StartMovement(PathCreator pathCreator)
        {
            if (_movement != null)
            {
                _movement.FollowPath(pathCreator);
            }
        }

        public void OnReachedEnd()
        {
            // 敌人走到终点也统计为波次敌人不再场
            EnemySpawner.OnEnemyKilled(gameObject, _birthWaveId);

            if (GameManager.Instance != null)
            {
                GameManager.Instance.TakeDamage(_enemyData.stats.lifeDamage);
            }
            EventBus.Publish(new EnemyReachEndEvent { Enemy = gameObject, Damage = _enemyData.stats.lifeDamage });
            Destroy(gameObject);
        }

        public void OnDeath()
        {
            // 波次统计-带上GameObject给HashSet去重
            EnemySpawner.OnEnemyKilled(gameObject, _birthWaveId);

            // 解绑事件
            if (_health != null)
            {
                _health.OnHealthChanged -= UpdateHealthBar;
                _health.OnDeath -= OnDeath;
            }

            // 隐藏血条
            if (_healthCanvas != null)
            {
                _healthCanvas.enabled = false;
            }

            if (GameManager.Instance != null)
            {
                GameManager.Instance.AddGold(_enemyData.stats.goldReward);
                GameManager.Instance.AddKill();
            }
            EventBus.Publish(new EnemyDeathEvent { Enemy = gameObject, Reward = _enemyData.stats.goldReward });
            Destroy(gameObject);
        }

        private void Update()
        {
            // 更新血条位置，始终在敌人头顶
            UpdateHealthBarPosition();
        }

        private void UpdateHealthBar(int currentHealth, int maxHealth)
        {
            if (_healthSlider == null) return;

            float healthPercent = (float)currentHealth / maxHealth;
            _healthSlider.value = healthPercent;

            // 根据血量改变颜色
            UpdateHealthBarColor(healthPercent);

            // 当血量低于最大值时显示血条
            if (_healthCanvas != null)
            {
                _healthCanvas.enabled = healthPercent < 1f;
            }
        }

        private void UpdateHealthBarColor(float healthPercent)
        {
            if (_healthFillImage == null) return;

            if (healthPercent <= 0.3f)
            {
                _healthFillImage.color = _lowHealthColor;
            }
            else if (healthPercent <= 0.6f)
            {
                _healthFillImage.color = _mediumHealthColor;
            }
            else
            {
                _healthFillImage.color = _highHealthColor;
            }
        }

        private void UpdateHealthBarPosition()
        {
            if (_healthSlider == null || _healthCanvas == null) return;

            // 将世界坐标转换为屏幕坐标
            Vector3 worldPosition = transform.position;
            worldPosition.y += _healthBarOffsetY;

            // 如果是世界空间画布，直接设置位置
            if (_healthCanvas.renderMode == RenderMode.WorldSpace)
            {
                _healthSlider.transform.position = worldPosition;
            }
            else
            {
                // 如果是屏幕空间画布，转换坐标
                Vector3 screenPosition = Camera.main.WorldToScreenPoint(worldPosition);
                _healthSlider.transform.position = screenPosition;
            }
        }

        private void OnDestroy()
        {
            // 确保解绑事件
            if (_health != null)
            {
                _health.OnHealthChanged -= UpdateHealthBar;
                _health.OnDeath -= OnDeath;
            }
        }

        public void TakeDamage(int damage)
        {
            if (_health != null)
            {
                _health.TakeDamage(damage);
            }
        }

        public void TakeDamage(int damage, DamageType damageType)
        {
            if (_health != null)
            {
                _health.TakeDamage(damage, damageType);
            }
        }

        public void ApplySlow(float slowFactor, float duration)
        {
            if (_movement != null)
            {
                _movement.Slow(slowFactor, duration);
            }
        }

        public void ApplyStun(float duration)
        {
            if (_movement != null)
            {
                _movement.Slow(0f, duration);
            }
        }
    }
}

using UnityEngine;
using UnityEngine.UI;

namespace TowerDefense.Enemy
{
    public class EnemyHealth : MonoBehaviour
    {
        [Header("Health Settings")]
        [SerializeField] private int _maxHealth = 100;
        [SerializeField] private int _goldReward = 10;

        [Header("UI Settings")]
        [SerializeField] private GameObject _healthBarPrefab;
        [SerializeField] private Vector3 _healthBarOffset = new Vector3(0, 1, 0);

        private int _currentHealth;
        private Slider _healthBarSlider;
        private Transform _healthBarTransform;

        public int CurrentHealth => _currentHealth;
        public int MaxHealth => _maxHealth;
        public float HealthPercentage => (float)_currentHealth / _maxHealth;

        public System.Action<int, int> OnHealthChanged;
        public System.Action OnDeath;

        private void Awake()
        {
            _currentHealth = _maxHealth;

            if (_healthBarPrefab != null)
            {
                CreateHealthBar();
            }
        }

        public void Initialize(int maxHealth, int goldReward)
        {
            _maxHealth = maxHealth;
            _currentHealth = maxHealth;
            _goldReward = goldReward;

            if (_healthBarSlider != null)
            {
                _healthBarSlider.maxValue = _maxHealth;
                _healthBarSlider.value = _currentHealth;
            }
        }

        private void CreateHealthBar()
        {
            Canvas canvas = FindObjectOfType<Canvas>();
            if (canvas == null) return;

            GameObject healthBarObj = Instantiate(_healthBarPrefab);
            healthBarObj.transform.SetParent(canvas.transform, false);

            _healthBarTransform = healthBarObj.transform;
            _healthBarSlider = healthBarObj.GetComponentInChildren<Slider>();

            if (_healthBarSlider != null)
            {
                _healthBarSlider.maxValue = _maxHealth;
                _healthBarSlider.value = _currentHealth;
            }
        }

        public void TakeDamage(int damage)
        {
            TakeDamage(damage, DamageType.Physical);
        }

        public void TakeDamage(int damage, DamageType damageType)
        {
            _currentHealth -= damage;
            _currentHealth = Mathf.Max(0, _currentHealth);

            // 触发血量变化事件
            OnHealthChanged?.Invoke(_currentHealth, _maxHealth);

            UpdateHealthBar();

            if (_currentHealth <= 0)
            {
                Die();
            }
        }

        private void UpdateHealthBar()
        {
            if (_healthBarTransform != null && _healthBarSlider != null)
            {
                _healthBarSlider.value = _currentHealth;

                Vector3 worldPos = Camera.main.WorldToScreenPoint(transform.position + _healthBarOffset);
                _healthBarTransform.position = worldPos;
            }
        }

        private void Die()
        {
            Destroy(_healthBarTransform?.gameObject);
            // 触发死亡事件
            OnDeath?.Invoke();
            SendMessage("OnDeath", SendMessageOptions.DontRequireReceiver);
        }

        private void OnDestroy()
        {
            Destroy(_healthBarTransform?.gameObject);
        }
    }
}

namespace TowerDefense.Enemy
{
    public enum DamageType
    {
        Physical,
        Magic,
        Explosion,
        Fire,
        Ice,
        Poison
    }
}

using System.Collections.Generic;
using UnityEngine;
using TowerDefense.Core;
using TowerDefense.Enemy;

namespace TowerDefense.Tower
{
    public class Projectile : MonoBehaviour
    {
        [Header("Movement Settings")]
        [SerializeField] private float _speed = 10f;
        [SerializeField] private float _homingStrength = 5f;

        [Header("Pierce Settings (Sword Tower)")]
        [SerializeField] private int _maxPierceCount = 3;
        [SerializeField] private float _maxLifetime = 3f;
        [SerializeField] private float _hitCooldown = 0.2f;

        [Header("Impact Settings")]
        [SerializeField] private GameObject _impactEffect;
        [SerializeField] private float _impactDuration = 1f;

        [Header("Debug")]
        [SerializeField] private bool _showDebugLogs = false;

        private Enemy.Enemy _target;
        private float _damage;
        private DamageType _damageType;
        private float _splashRadius = 0f;
        private int _maxSplashTargets = 0;
        private bool _hasHit = false;

        private bool _isPierceMode = false;
        private List<Enemy.Enemy> _hitEnemies = new List<Enemy.Enemy>();
        private int _currentPierceCount = 0;
        private Vector3 _moveDirection;
        private float _lifetimeTimer = 0f;
        private float _lastHitTime = 0f;

        public void Initialize(Enemy.Enemy target, float damage, DamageType damageType, float splashRadius = 0f, int pierceCount = 0, int maxSplashTargets = 0)
        {
            _target = target;
            _damage = damage;
            _damageType = damageType;
            _splashRadius = splashRadius;
            _maxSplashTargets = maxSplashTargets;
            _hasHit = false;

            _isPierceMode = pierceCount > 0;

            if (_isPierceMode)
            {
                _maxPierceCount = pierceCount;
                if (target != null)
                {
                    _moveDirection = (target.transform.position - transform.position).normalized;
                }
                else
                {
                    _moveDirection = transform.up;
                }

                float angle = Mathf.Atan2(_moveDirection.y, _moveDirection.x) * Mathf.Rad2Deg - 90f;
                transform.rotation = Quaternion.AngleAxis(angle, Vector3.forward);

                if (_showDebugLogs)
                {
                    Debug.Log($"⚔️ 穿透模式: maxPierce={_maxPierceCount}, dir=({_moveDirection.x:F2},{_moveDirection.y:F2})");
                }
            }

            _hitEnemies.Clear();
            _currentPierceCount = 0;
            _lifetimeTimer = 0f;
            _lastHitTime = 0f;
        }

        private void Update()
        {
            if (_isPierceMode)
            {
                UpdatePierceMovement();
                return;
            }

            if (_target == null || _target.IsDead)
            {
                FindNewTarget();
                if (_target == null)
                {
                    Destroy(gameObject);
                    return;
                }
            }

            MoveTowardsTarget();
        }

        private void UpdatePierceMovement()
        {
            _lifetimeTimer += Time.deltaTime;

            if (_lifetimeTimer >= _maxLifetime || _currentPierceCount >= _maxPierceCount)
            {
                if (_showDebugLogs)
                {
                    Debug.Log($"穿透结束: life={_lifetimeTimer:F1}s, hits={_currentPierceCount}");
                }
                DestroyProjectile();
                return;
            }

            transform.position += _moveDirection * _speed * Time.deltaTime;

            CheckPierceHits();
        }

        private void CheckPierceHits()
        {
            if (Time.time - _lastHitTime < _hitCooldown) return;

            float hitRange = 0.5f;

            Enemy.Enemy[] allEnemies = FindObjectsOfType<Enemy.Enemy>();
            List<Enemy.Enemy> enemiesInRange = new List<Enemy.Enemy>();

            foreach (var enemy in allEnemies)
            {
                if (enemy == null || enemy.IsDead) continue;

                float dist = Vector3.Distance(transform.position, enemy.transform.position);
                if (dist <= hitRange)
                {
                    enemiesInRange.Add(enemy);
                }
            }

            if (_showDebugLogs && enemiesInRange.Count > 0)
            {
                Debug.Log($"范围内有 {enemiesInRange.Count} 个敌人, 已击中: {_hitEnemies.Count}");
            }

            foreach (var enemy in enemiesInRange)
            {
                if (_hitEnemies.Contains(enemy)) continue;

                if (_showDebugLogs)
                {
                    Debug.Log($"💥 击中敌人! {enemy.name}, 第 {_currentPierceCount + 1}/{_maxPierceCount} 次");
                }

                DealDamageToEnemy(enemy);
                _hitEnemies.Add(enemy);
                _currentPierceCount++;
                _lastHitTime = Time.time;

                PlayImpactEffect();

                if (_currentPierceCount >= _maxPierceCount)
                {
                    DestroyProjectile();
                    return;
                }
            }
        }

        private void MoveTowardsTarget()
        {
            if (_target == null) return;

            Vector3 targetPosition = _target.transform.position;
            Vector3 direction = (targetPosition - transform.position).normalized;

            transform.position += direction * _speed * Time.deltaTime;

            float angle = Mathf.Atan2(direction.y, direction.x) * Mathf.Rad2Deg - 90f;
            transform.rotation = Quaternion.AngleAxis(angle, Vector3.forward);

            float distance = Vector3.Distance(transform.position, targetPosition);
            if (distance <= 0.5f)
            {
                HitTarget();
            }
        }

        private void FindNewTarget()
        {
            EnemySpawner spawner = FindObjectOfType<EnemySpawner>();
            if (spawner != null)
            {
                _target = spawner.GetClosestEnemy(transform.position, 500f);
            }
        }

        private void HitTarget()
        {
            if (_hasHit) return;
            _hasHit = true;

            if (_splashRadius > 0)
            {
                DealSplashDamage();
            }
            else
            {
                DealSingleTargetDamage();
            }

            PlayImpactEffect();
            Destroy(gameObject);
        }

        private void DealSingleTargetDamage()
        {
            if (_target != null && !_target.IsDead)
            {
                _target.Health.TakeDamage(Mathf.RoundToInt(_damage), _damageType);
            }
        }

        private void DealDamageToEnemy(Enemy.Enemy enemy)
        {
            if (enemy != null && !enemy.IsDead)
            {
                enemy.Health.TakeDamage(Mathf.RoundToInt(_damage), _damageType);
            }
        }

        private void DealSplashDamage()
        {
            EnemySpawner spawner = FindObjectOfType<EnemySpawner>();
            if (spawner == null) return;

            List<Enemy.Enemy> enemiesInSplash = spawner.GetEnemiesInRange(transform.position, _splashRadius);

            // 按距离排序，近的优先
            enemiesInSplash.Sort((a, b) =>
            {
                float distA = Vector3.Distance(transform.position, a.transform.position);
                float distB = Vector3.Distance(transform.position, b.transform.position);
                return distA.CompareTo(distB);
            });

            int hitCount = 0;
            foreach (var enemy in enemiesInSplash)
            {
                if (enemy == null || enemy.IsDead) continue;

                // 如果设了上限，达到数量后停止
                if (_maxSplashTargets > 0 && hitCount >= _maxSplashTargets) break;

                float distance = Vector3.Distance(transform.position, enemy.transform.position);
                float damageMultiplier = 1f - (distance / _splashRadius) * 0.5f;
                int damage = Mathf.RoundToInt(_damage * damageMultiplier);
                enemy.Health.TakeDamage(damage, _damageType);
                hitCount++;
            }
        }

        private void PlayImpactEffect()
        {
            if (_impactEffect != null)
            {
                GameObject effect = Instantiate(_impactEffect, transform.position, Quaternion.identity);
                Destroy(effect, _impactDuration);
            }
        }

        private void DestroyProjectile()
        {
            _hasHit = true;
            Destroy(gameObject);
        }

        private void OnTriggerEnter2D(Collider2D other)
        {
            if (_isPierceMode) return;

            Enemy.Enemy enemy = other.GetComponent<Enemy.Enemy>();
            if (enemy != null && enemy == _target)
            {
                HitTarget();
            }
        }
    }
}

using System.Collections;
using System.Collections.Generic;
using UnityEngine;
using TowerDefense.Data;
using TowerDefense.Enemy;
using TowerDefense.Utils;

namespace TowerDefense.Tower
{
    public class BarracksAttack : TowerAttack
    {
        [Header("Barracks Settings")]
        [SerializeField] private SoldierData _soldierData;
        [SerializeField] private float _spawnRadius = 0.5f;

        [Header("Rally Point")]
        [SerializeField] private Transform _rallyPoint;
        [SerializeField] private float _rallyPointRange = 3f;
        [SerializeField] private GameObject _rallyPointMarker;
        [SerializeField] private bool _rallyPointDraggable = true;

        private List<Soldier> _soldiers = new List<Soldier>();
        private int _maxSoldiers = 3;
        private bool _soldiersSpawned = false;

        public List<Soldier> Soldiers => _soldiers;
        public Transform RallyPoint => _rallyPoint;
        public float RallyPointRange => _rallyPointRange;

        public int AliveSoldierCount
        {
            get
            {
                int count = 0;
                foreach (var s in _soldiers)
                    if (s != null && s.IsAlive) count++;
                return count;
            }
        }

        public override void Initialize(Tower tower)
        {
            base.Initialize(tower);

            // Determine max soldiers from tower data
            if (_tower.Data != null && _tower.Data.soldierCountPerLevel != null
                && _tower.Data.soldierCountPerLevel.Length > 0)
            {
                int levelIndex = Mathf.Clamp(_tower.CurrentLevel - 1, 0, _tower.Data.soldierCountPerLevel.Length - 1);
                _maxSoldiers = _tower.Data.soldierCountPerLevel[levelIndex];
            }
            else
            {
                _maxSoldiers = _tower.CurrentLevel switch
                {
                    1 => 3,
                    2 => 5,
                    3 => 7,
                    _ => 3
                };
            }

            if (_soldierData == null && _tower.Data != null)
                _soldierData = _tower.Data.soldierData;

            SetupRallyPoint();
        }

        /// <summary>
        /// Setup the rally point. If not assigned, find the closest point on the enemy path.
        /// In Kingdom Rush, soldiers stand at the rally point and engage enemies from there.
        /// </summary>
        private void SetupRallyPoint()
        {
            // Create rally point object if not assigned
            if (_rallyPoint == null)
            {
                var rallyObj = new GameObject("RallyPoint");
                rallyObj.transform.SetParent(transform);
                rallyObj.transform.position = FindDefaultRallyPosition();
                _rallyPoint = rallyObj.transform;
            }

            // Create visual marker
            if (_rallyPointMarker == null)
            {
                _rallyPointMarker = CreateRallyPointMarker();
            }

            _rallyPointMarker.transform.SetParent(_rallyPoint);
            _rallyPointMarker.transform.localPosition = Vector3.zero;
            _rallyPointMarker.SetActive(true);
        }

        /// <summary>
        /// Find the default rally position: closest point on the enemy path to the tower.
        /// This is the Kingdom Rush behavior — soldiers rally near the path, not at the tower.
        /// </summary>
        private Vector3 FindDefaultRallyPosition()
        {
            var pathCreator = FindObjectOfType<PathCreator>();
            if (pathCreator != null && pathCreator.WaypointCount > 0)
            {
                Vector3 closestPoint = Vector3.zero;
                float closestDist = float.MaxValue;

                // Check interpolated path points for closest to tower
                var smoothPath = pathCreator.GetSmoothPath(20);
                foreach (var pathPoint in smoothPath)
                {
                    float dist = Vector3.Distance(transform.position, pathPoint);
                    if (dist < closestDist)
                    {
                        closestDist = dist;
                        closestPoint = pathPoint;
                    }
                }

                // Offset slightly off-path so soldiers aren't standing ON the path
                Vector3 awayFromPath = (transform.position - closestPoint).normalized;
                if (awayFromPath == Vector3.zero) awayFromPath = Vector3.up;
                closestPoint += awayFromPath * 0.8f;

                return closestPoint;
            }

            // Fallback: just offset from tower towards path center
            return transform.position + Vector3.right * _rallyPointRange * 0.7f;
        }

        private GameObject CreateRallyPointMarker()
        {
            var marker = new GameObject("RallyPointMarker");
            var sr = marker.AddComponent<SpriteRenderer>();
            sr.sprite = CreateCircleSprite();
            sr.color = new Color(1f, 0.8f, 0f, 0.4f);
            sr.sortingOrder = -1;
            marker.transform.localScale = new Vector3(_rallyPointRange * 2f, _rallyPointRange * 2f, 1f);
            return marker;
        }

        private Sprite CreateCircleSprite()
        {
            int size = 64;
            var tex = new Texture2D(size, size);
            var center = new Vector2(size / 2f, size / 2f);
            float radius = size / 2f - 2f;

            for (int y = 0; y < size; y++)
            {
                for (int x = 0; x < size; x++)
                {
                    float dist = Vector2.Distance(new Vector2(x, y), center);
                    if (dist > radius - 1f && dist < radius + 1f)
                        tex.SetPixel(x, y, Color.white);
                    else
                        tex.SetPixel(x, y, Color.clear);
                }
            }
            tex.Apply();
            return Sprite.Create(tex, new Rect(0, 0, size, size), new Vector2(0.5f, 0.5f));
        }

        /// <summary>
        /// Move rally point to a new position (called by drag handler).
        /// Clamped within tower's attack range.
        /// </summary>
        public void MoveRallyPoint(Vector3 newPosition)
        {
            // Clamp to within attack range of tower
            float maxDist = GetEffectiveAttackRange();
            Vector3 dir = newPosition - transform.position;
            if (dir.magnitude > maxDist)
            {
                newPosition = transform.position + dir.normalized * maxDist;
            }

            _rallyPoint.position = newPosition;

            // Move idle soldiers to new rally point
            foreach (var soldier in _soldiers)
            {
                if (soldier != null && soldier.IsAlive && soldier.State == SoldierState.Idle)
                {
                    soldier.SetRallyPoint(_rallyPoint);
                }
            }
        }

        protected override void Update()
        {
            base.Update();
            AutoAssignTargets();
        }

        public override void Attack(Enemy.Enemy target)
        {
            if (target == null || target.IsDead) return;

            if (!_soldiersSpawned)
            {
                SpawnAllSoldiers();
                _soldiersSpawned = true;
            }

            AssignTarget(target);
        }

        protected override void SpawnSoldiers(Enemy.Enemy target)
        {
            if (_soldierData == null || _soldierData.soldierPrefab == null)
            {
                Debug.LogWarning("BarracksAttack: SoldierData or prefab is null!");
                return;
            }

            if (!_soldiersSpawned)
            {
                SpawnAllSoldiers();
                _soldiersSpawned = true;
            }

            AssignTarget(target);
        }

        private void SpawnAllSoldiers()
        {
            ClearDeadSoldiers();

            int toSpawn = _maxSoldiers - _soldiers.Count;
            Vector3 basePos = _rallyPoint != null ? _rallyPoint.position : transform.position;

            for (int i = 0; i < toSpawn; i++)
            {
                float angle = (2f * Mathf.PI * i) / _maxSoldiers;
                Vector3 offset = new Vector3(
                    Mathf.Cos(angle) * _spawnRadius,
                    Mathf.Sin(angle) * _spawnRadius,
                    0f
                );
                Vector3 spawnPos = basePos + offset;

                GameObject soldierObj = Instantiate(_soldierData.soldierPrefab, spawnPos, Quaternion.identity);
                // Don't parent under tower — non-uniform parent scale breaks child positioning

                Soldier soldier = soldierObj.GetComponent<Soldier>();
                if (soldier == null)
                {
                    soldier = soldierObj.AddComponent<Soldier>();
                }

                soldier.Initialize(_soldierData, _rallyPoint);
                soldier.OnSoldierDeath += OnSoldierDeath;
                _soldiers.Add(soldier);
            }

            Debug.Log($"Barracks spawned {toSpawn} soldiers at rally point (total: {_soldiers.Count})");
        }

        private void AssignTarget(Enemy.Enemy target)
        {
            if (target == null || target.IsDead) return;

            foreach (var soldier in _soldiers)
            {
                if (soldier != null && soldier.IsAlive && soldier.State == SoldierState.Idle)
                {
                    soldier.EngageTarget(target);
                }
            }
        }

        /// <summary>
        /// Auto-assign idle soldiers to enemies within rally point range.
        /// In Kingdom Rush, soldiers detect enemies from their rally point, not the tower.
        /// </summary>
        private void AutoAssignTargets()
        {
            if (_tower == null) return;

            List<Soldier> idleSoldiers = new List<Soldier>();
            foreach (var s in _soldiers)
            {
                if (s != null && s.IsAlive && s.State == SoldierState.Idle)
                    idleSoldiers.Add(s);
            }

            if (idleSoldiers.Count == 0) return;

            EnemySpawner spawner = FindObjectOfType<EnemySpawner>();
            if (spawner == null) return;

            // Search from rally point, not tower position
            Vector3 searchOrigin = _rallyPoint != null ? _rallyPoint.position : transform.position;
            float searchRange = _soldierData != null ? _soldierData.engageRange : 3f;
            var enemiesInRange = spawner.GetEnemiesInRange(searchOrigin, searchRange);

            foreach (var soldier in idleSoldiers)
            {
                Enemy.Enemy bestTarget = null;
                float bestDist = float.MaxValue;

                foreach (var enemy in enemiesInRange)
                {
                    if (enemy == null || enemy.IsDead) continue;

                    float dist = Vector3.Distance(soldier.transform.position, enemy.transform.position);
                    if (dist < bestDist)
                    {
                        bestDist = dist;
                        bestTarget = enemy;
                    }
                }

                if (bestTarget != null)
                {
                    soldier.EngageTarget(bestTarget);
                }
            }
        }

        private void OnSoldierDeath(Soldier soldier)
        {
            soldier.OnSoldierDeath -= OnSoldierDeath;
            StartCoroutine(RespawnSoldierAfterDelay(soldier, _soldierData.respawnTime));
        }

        private IEnumerator RespawnSoldierAfterDelay(Soldier soldier, float delay)
        {
            yield return new WaitForSeconds(delay);

            if (soldier != null && _tower != null)
            {
                Vector3 basePos = _rallyPoint != null ? _rallyPoint.position : transform.position;
                float angle = Random.Range(0f, 2f * Mathf.PI);
                Vector3 offset = new Vector3(
                    Mathf.Cos(angle) * _spawnRadius,
                    Mathf.Sin(angle) * _spawnRadius,
                    0f
                );
                soldier.Respawn(basePos + offset);
                soldier.SetRallyPoint(_rallyPoint);
                soldier.OnSoldierDeath += OnSoldierDeath;
                Debug.Log("Barracks soldier respawned at rally point");
            }
        }

        private void ClearDeadSoldiers()
        {
            for (int i = _soldiers.Count - 1; i >= 0; i--)
            {
                if (_soldiers[i] == null)
                {
                    _soldiers.RemoveAt(i);
                }
            }
        }

        public override bool CanAttack()
        {
            return !_soldiersSpawned || AliveSoldierCount > 0;
        }

        public override float GetEffectiveAttackRange()
        {
            return _soldierData != null ? _soldierData.engageRange : 3f;
        }

        private void OnDestroy()
        {
            foreach (var soldier in _soldiers)
            {
                if (soldier != null)
                {
                    soldier.OnSoldierDeath -= OnSoldierDeath;
                    Destroy(soldier.gameObject);
                }
            }
            _soldiers.Clear();
        }

        private void OnDrawGizmosSelected()
        {
            // Draw rally point range
            if (_rallyPoint != null)
            {
                Gizmos.color = new Color(1f, 0.8f, 0f, 0.3f);
                Gizmos.DrawWireSphere(_rallyPoint.position, _rallyPointRange);
            }
        }
    }
}

using UnityEngine;
using System.Collections.Generic;
using TowerDefense.Data;
using TowerDefense.Utils;
using TowerDefense.Wave;

namespace TowerDefense.Enemy
{
    public class EnemySpawner : MonoBehaviour
    {
        [Header("Settings")]
        [SerializeField] private PathCreator _pathCreator;
        [SerializeField] private Transform _spawnPoint;

        private void Awake()
        {
            if (_pathCreator == null)
            {
                _pathCreator = FindObjectOfType<PathCreator>();
                if (_pathCreator != null)
                    Debug.Log("EnemySpawner: 自动找到 PathCreator - " + _pathCreator.gameObject.name);
                else
                    Debug.LogError("EnemySpawner: 找不到 PathCreator！");
            }
        }

        private Queue<EnemyData> _spawnQueue = new Queue<EnemyData>();
        private float _spawnTimer = 0f;
        private float _spawnInterval = 1f;
        private bool _isSpawning = false;
        private bool _allSpawned = false; // 标记是否所有敌人都已出生

        public bool IsSpawning => _isSpawning;
        public static int CurrentWaveId { get; private set; }
        public static int TotalEnemiesInWave { get; private set; }

        // 双保险：本波 HashSet 防止重复统计
        private static HashSet<GameObject> _killedEnemiesThisWave = new HashSet<GameObject>();

        public static int RemainingEnemies 
        { 
            get 
            { 
                int remaining = TotalEnemiesInWave - _killedEnemiesThisWave.Count;
                return remaining >= 0 ? remaining : 0;  // 保证非负
            } 
        }

        private void Update()
        {
            if (_isSpawning && _spawnQueue.Count > 0)
            {
                _spawnTimer += Time.deltaTime;

                if (_spawnTimer >= _spawnInterval)
                {
                    _spawnTimer = 0f;
                    SpawnEnemy();
                }
            }

            // 所有敌人都已出生，且全部死亡/到达终点，才通知波次完成
            if (_allSpawned && RemainingEnemies <= 0)
            {
                _isSpawning = false;
                _allSpawned = false;
                WaveManager.Instance?.OnWaveComplete();
            }
        }

        public static void EnemyBorn(GameObject enemy)
        {
            // 敌人出生时注册波次ID
            enemy.GetComponent<Enemy>()?.SetBirthWaveId(CurrentWaveId);
        }

        public static void OnEnemyKilled(GameObject enemy, int enemyWaveId)
        {
            // ✅ 双保险: HashSet去重 + 波次ID相等才统计
            if (!_killedEnemiesThisWave.Contains(enemy) && enemyWaveId == CurrentWaveId)
            {
                _killedEnemiesThisWave.Add(enemy);
                Debug.Log($"✅ 波次{CurrentWaveId}敌人死亡: {_killedEnemiesThisWave.Count}/{TotalEnemiesInWave}, 剩余: {RemainingEnemies}");
            }
        }

        public void StartWave(WaveData waveData)
        {
            _spawnQueue.Clear();

            // 波次递进，给新的ID
            CurrentWaveId++;
            TotalEnemiesInWave = 0;

            // ✅ 新波次: 清空死亡集合，防止死循环统计
            _killedEnemiesThisWave.Clear();

            foreach (var enemyGroup in waveData.enemies)
            {
                for (int i = 0; i < enemyGroup.count; i++)
                {
                    _spawnQueue.Enqueue(enemyGroup.enemyData);
                    TotalEnemiesInWave++;
                }
            }

            Debug.Log($"🌊 波次{CurrentWaveId}开始: 准备出生 {TotalEnemiesInWave} 个敌人");

            _spawnInterval = waveData.spawnInterval;
            _isSpawning = true;
            _allSpawned = false;
            _spawnTimer = 0f;

            Debug.Log($"Wave started! Enemies to spawn: {_spawnQueue.Count}");
        }

        private void SpawnEnemy()
        {
            if (_spawnQueue.Count == 0)
            {
                _allSpawned = true;
                return;
            }

            EnemyData enemyData = _spawnQueue.Dequeue();

            // 队列空了，标记所有敌人都已出生
            if (_spawnQueue.Count == 0)
            {
                _allSpawned = true;
            }

            if (enemyData == null || enemyData.enemyPrefab == null)
            {
                SpawnEnemy();
                return;
            }

            Vector3 spawnPos = _spawnPoint != null ? _spawnPoint.position : (_pathCreator != null ? _pathCreator.GetWaypoint(0) : transform.position);

            GameObject enemyObj = Instantiate(enemyData.enemyPrefab, spawnPos, Quaternion.identity);
            Enemy enemy = enemyObj.GetComponent<Enemy>();

            if (enemy != null && _pathCreator != null)
            {
                // ✅ 设置波次归属ID（HashSet去重统计要用）
                enemy.SetBirthWaveId(CurrentWaveId);
                enemy.Initialize(enemyData);
                enemy.StartMovement(_pathCreator);
            }

            Debug.Log($"Spawned enemy: {enemyData.enemyName}, 波次ID={CurrentWaveId}");
        }

        public void StopSpawning()
        {
            _isSpawning = false;
            _spawnQueue.Clear();
        }

        public Enemy GetClosestEnemy(Vector3 position, float maxDistance)
        {
            Enemy[] enemies = FindObjectsOfType<Enemy>();
            Enemy closestEnemy = null;
            float closestDistance = float.MaxValue;

            foreach (var enemy in enemies)
            {
                float distance = Vector3.Distance(position, enemy.transform.position);
                if (distance <= maxDistance && distance < closestDistance)
                {
                    closestDistance = distance;
                    closestEnemy = enemy;
                }
            }

            return closestEnemy;
        }

        public List<Enemy> GetEnemiesInRange(Vector3 position, float range)
        {
            List<Enemy> enemiesInRange = new List<Enemy>();
            Enemy[] enemies = FindObjectsOfType<Enemy>();

            foreach (var enemy in enemies)
            {
                float distance = Vector3.Distance(position, enemy.transform.position);
                if (distance <= range)
                {
                    enemiesInRange.Add(enemy);
                }
            }

            return enemiesInRange;
        }

        private void OnDrawGizmos()
        {
            Gizmos.color = Color.cyan;
            Vector3 spawnPos = _spawnPoint != null ? _spawnPoint.position : transform.position;
            Gizmos.DrawSphere(spawnPos, 0.3f);
        }
    }
}

using System.Collections;
using UnityEngine;
using TowerDefense.Data;
using TowerDefense.Enemy;
using TowerDefense.Utils;

namespace TowerDefense.Tower
{
    public enum SoldierState
    {
        Idle,
        MovingToEnemy,
        Attacking,
        Returning
    }

    public class Soldier : MonoBehaviour
    {
        [Header("References")]
        [SerializeField] private SpriteRenderer _spriteRenderer;
        [SerializeField] private Animator _animator;

        private static readonly int RunHash = Animator.StringToHash("Run");
        private static readonly int IdleHash = Animator.StringToHash("Idle");

        private SoldierData _data;
        private Transform _homePoint;
        private int _currentHealth;
        private Enemy.Enemy _target;
        private SoldierState _state = SoldierState.Idle;
        private float _attackCooldown = 0f;
        private float _enemyAttackCooldown = 0f;
        private bool _isAlive = true;
        private bool _isBlocking = false;
        private float _healTimer = 0f;
        private float _healInterval = 1f;

        public bool IsAlive => _isAlive;
        public bool IsBlocking => _isBlocking;
        public SoldierState State => _state;
        public Enemy.Enemy CurrentTarget => _target;
        public int CurrentHealth => _currentHealth;
        public float HealthPercent => _data != null ? (float)_currentHealth / _data.maxHealth : 0f;

        public System.Action<Soldier> OnSoldierDeath;
        public System.Action<Soldier> OnSoldierReturned;

        public void Initialize(SoldierData data, Transform homePoint)
        {
            _data = data;
            _homePoint = homePoint;
            _currentHealth = data.maxHealth;
            _isAlive = true;
            _isBlocking = false;
            _state = SoldierState.Idle;
            _target = null;
            _attackCooldown = 0f;
            _healTimer = 0f;

            if (_spriteRenderer == null)
                _spriteRenderer = GetComponent<SpriteRenderer>();

            if (_animator == null)
                _animator = GetComponent<Animator>();

            PlayIdleAnimation();
            gameObject.SetActive(true);
        }

        public void SetRallyPoint(Transform rallyPoint)
        {
            _homePoint = rallyPoint;
        }

        private void Update()
        {
            if (!_isAlive || _data == null) return;

            switch (_state)
            {
                case SoldierState.Idle:
                    FindEnemy();
                    HealOutOfCombat();
                    break;
                case SoldierState.MovingToEnemy:
                    MoveTowardsEnemy();
                    break;
                case SoldierState.Attacking:
                    AttackEnemy();
                    break;
                case SoldierState.Returning:
                    ReturnToRallyPoint();
                    break;
            }
        }

        private void FindEnemy()
        {
            Vector3 searchOrigin = _homePoint != null ? _homePoint.position : transform.position;

            EnemySpawner spawner = FindObjectOfType<EnemySpawner>();
            if (spawner == null) return;

            var enemies = spawner.GetEnemiesInRange(searchOrigin, _data.engageRange);
            if (enemies.Count > 0)
            {
                float closestDist = float.MaxValue;
                Enemy.Enemy closest = null;
                foreach (var e in enemies)
                {
                    if (e == null || e.IsDead) continue;
                    float dist = Vector2.Distance(transform.position, e.transform.position);
                    if (dist < closestDist)
                    {
                        closestDist = dist;
                        closest = e;
                    }
                }

                if (closest != null)
                {
                    _target = closest;
                    _state = SoldierState.MovingToEnemy;
                    PlayRunAnimation();
                }
            }
        }

        private void MoveTowardsEnemy()
        {
            if (_target == null || _target.IsDead || _target.gameObject == null)
            {
                ReleaseTarget();
                _state = SoldierState.Returning;
                return;
            }

            Vector2 currentPos = transform.position;
            float dist = Vector2.Distance(currentPos, (Vector2)_target.transform.position);
            if (dist <= _data.attackRange)
            {
                _state = SoldierState.Attacking;
                BlockEnemy();
                return;
            }

            if (_homePoint != null)
            {
                float distFromHome = Vector2.Distance((Vector2)_target.transform.position, (Vector2)_homePoint.position);
                if (distFromHome > _data.engageRange * 1.5f)
                {
                    ReleaseTarget();
                    _state = SoldierState.Returning;
                    return;
                }
            }

            Vector2 direction = ((Vector2)_target.transform.position - currentPos).normalized;
            transform.position += (Vector3)(direction * _data.moveSpeed * Time.deltaTime);

            if (_spriteRenderer != null)
                _spriteRenderer.flipX = direction.x < 0;
        }

        private void AttackEnemy()
        {
            if (_target == null || _target.IsDead || _target.gameObject == null)
            {
                ReleaseTarget();
                _state = SoldierState.Returning;
                return;
            }

            float dist = Vector2.Distance(transform.position, _target.transform.position);
            if (dist > _data.attackRange * 2f)
            {
                ReleaseTarget();
                _state = SoldierState.MovingToEnemy;
                return;
            }

            _attackCooldown -= Time.deltaTime;
            if (_attackCooldown <= 0f)
            {
                _target.TakeDamage(_data.damage, DamageType.Physical);
                _attackCooldown = 1f / _data.attackSpeed;
            }

            EnemyAttacksSoldier();
        }

        private void EnemyAttacksSoldier()
        {
            if (_target == null || _target.IsDead) return;

            var enemyData = _target.Data;
            if (enemyData == null) return;

            _enemyAttackCooldown -= Time.deltaTime;
            if (_enemyAttackCooldown <= 0f)
            {
                int enemyDamage = enemyData.stats.attackDamage;
                if (enemyDamage <= 0)
                    enemyDamage = Mathf.Max(1, Mathf.CeilToInt(enemyData.stats.maxHealth * 0.05f));
                TakeDamage(enemyDamage);
                _enemyAttackCooldown = 1f;
            }
        }

        private void BlockEnemy()
        {
            if (_target == null || _isBlocking) return;

            _isBlocking = true;
            var movement = _target.GetComponent<EnemyMovement>();
            if (movement != null)
            {
                movement.StopMovement();
            }
        }

        private void ReleaseTarget()
        {
            if (_isBlocking && _target != null)
            {
                var movement = _target.GetComponent<EnemyMovement>();
                if (movement != null && _target.gameObject != null && !_target.IsDead)
                {
                    var pathCreator = FindObjectOfType<PathCreator>();
                    if (pathCreator != null)
                    {
                        movement.FollowPath(pathCreator);
                    }
                    else
                    {
                        movement.SetSpeed(movement.GetSpeed() > 0 ? movement.GetSpeed() : 2f);
                    }
                }
            }

            _isBlocking = false;
            _target = null;
        }

        private void ReturnToRallyPoint()
        {
            if (_homePoint == null)
            {
                _state = SoldierState.Idle;
                return;
            }

            float dist = Vector2.Distance(transform.position, _homePoint.position);
            if (dist <= 0.3f)
            {
                _state = SoldierState.Idle;
                PlayIdleAnimation();
                OnSoldierReturned?.Invoke(this);
                return;
            }

            Vector2 direction = ((Vector2)_homePoint.position - (Vector2)transform.position).normalized;
            transform.position += (Vector3)(direction * _data.returnSpeed * Time.deltaTime);

            if (_spriteRenderer != null)
                _spriteRenderer.flipX = direction.x < 0;
        }

        private void HealOutOfCombat()
        {
            if (_data == null || _currentHealth >= _data.maxHealth) return;

            _healTimer += Time.deltaTime;
            if (_healTimer >= _healInterval)
            {
                _healTimer = 0f;
                _currentHealth = Mathf.Min(_currentHealth + 1, _data.maxHealth);
            }
        }

        public void TakeDamage(int damage)
        {
            if (!_isAlive) return;

            _currentHealth -= damage;
            if (_currentHealth <= 0)
            {
                Die();
            }
        }

        private void Die()
        {
            _isAlive = false;
            ReleaseTarget();
            _state = SoldierState.Idle;
            OnSoldierDeath?.Invoke(this);
            gameObject.SetActive(false);
        }

        public void Respawn(Vector3 position)
        {
            _currentHealth = _data.maxHealth;
            _isAlive = true;
            _isBlocking = false;
            _state = SoldierState.Idle;
            _target = null;
            _attackCooldown = 0f;
            _enemyAttackCooldown = 0f;
            _healTimer = 0f;

            transform.SetParent(null);
            transform.position = position;

            PlayIdleAnimation();
            gameObject.SetActive(true);
        }

        public void EngageTarget(Enemy.Enemy target)
        {
            if (!_isAlive || target == null || target.IsDead) return;
            _target = target;
            _state = SoldierState.MovingToEnemy;
            PlayRunAnimation();
        }

        private void OnDestroy()
        {
            if (_isBlocking && _target != null)
            {
                var movement = _target.GetComponent<EnemyMovement>();
                if (movement != null && _target.gameObject != null && !_target.IsDead)
                {
                    var pathCreator = FindObjectOfType<PathCreator>();
                    if (pathCreator != null)
                        movement.FollowPath(pathCreator);
                }
            }
        }

        private void PlayIdleAnimation()
        {
            if (_animator != null)
            {
                _animator.SetBool(RunHash, false);
                _animator.SetBool(IdleHash, true);
            }
        }

        private void PlayRunAnimation()
        {
            if (_animator != null)
            {
                _animator.SetBool(IdleHash, false);
                _animator.SetBool(RunHash, true);
            }
        }
    }
}

using System.Collections.Generic;
using UnityEngine;
using TowerDefense.Core;
using TowerDefense.Enemy;

namespace TowerDefense.Skill
{
    public enum SkillTargetType
    {
        Self,
        Enemy,
        Area,
        Direction
    }

    public abstract class SkillBase : ScriptableObject
    {
        [Header("Skill Info")]
        public string skillName;
        public string description;
        public Sprite icon;
        public int maxLevel = 5;

        [Header("Cooldown & Cost")]
        public float cooldown = 10f;
        public int manaCost = 0;
        public int goldCost = 0;

        [Header("Targeting")]
        public SkillTargetType targetType = SkillTargetType.Area;
        public float range = 5f;
        public float radius = 2f;

        [Header("Effects")]
        public GameObject effectPrefab;
        public AudioClip soundEffect;

        protected int _currentLevel = 1;

        public int CurrentLevel => _currentLevel;

        public virtual bool CanUse(GameObject user)
        {
            if (goldCost > 0 && !GameManager.Instance.HasEnoughGold(goldCost))
            {
                return false;
            }
            return true;
        }

        public virtual void Use(GameObject user, Vector3 targetPosition)
        {
            if (!CanUse(user)) return;

            if (goldCost > 0)
            {
                GameManager.Instance.SpendGold(goldCost);
            }

            Execute(user, targetPosition);
            PlayEffects(targetPosition);

            EventBus.Publish(new SkillUsedEvent { SkillName = skillName });
        }

        protected abstract void Execute(GameObject user, Vector3 targetPosition);

        protected virtual void PlayEffects(Vector3 position)
        {
            if (effectPrefab != null)
            {
                Instantiate(effectPrefab, position, Quaternion.identity);
            }

            if (soundEffect != null)
            {
                AudioSource.PlayClipAtPoint(soundEffect, position);
            }
        }

        public virtual void Upgrade()
        {
            if (_currentLevel < maxLevel)
            {
                _currentLevel++;
            }
        }

        protected List<Enemy.Enemy> GetEnemiesInRadius(Vector3 center, float radius)
        {
            EnemySpawner spawner = FindObjectOfType<EnemySpawner>();
            if (spawner == null) return new List<Enemy.Enemy>();

            return spawner.GetEnemiesInRange(center, radius);
        }
    }
}

